#include <bits/stdc++.h>
using namespace std;

int findLastPerson(int n, int k) {
    if(n == 1) return 1;

    // recursive solution using 0-based indexing
    // convert back to 1-based indexing at end
    return (findLastPerson(n - 1, k) + k - 1) % n + 1;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n, k;
        cin >> n >> k;
        cout << findLastPerson(n, k) << endl;
    }

    return 0;
}
